from sys import stdin, stdout

garland = list(stdin.readline().strip())
n = len(garland)
kr, kb, ky, kg = 0, 0, 0, 0
colors = {'R', 'B', 'Y', 'G'}

def get_possible_colors(garland, index):
    forbidden = set()
    for i in range(max(0, index - 3), min(n, index + 4)):
        if garland[i] != '!' and i != index:
            forbidden.add(garland[i])
    return colors - forbidden

while True:
    changed = False
    for i in range(n):
        if garland[i] == '!':
            possible = get_possible_colors(garland, i)
            if len(possible) == 1:
                color = possible.pop()
                garland[i] = color
                if color == 'R':
                    kr += 1
                elif color == 'B':
                    kb += 1
                elif color == 'Y':
                    ky += 1
                elif color == 'G':
                    kg += 1
                changed = True
    if not changed:
        break

